import{_ as a,o as t,c as i,ag as o}from"./chunks/framework.ePeAWSvT.js";const p=JSON.parse('{"title":"Features","description":"Verified product features and UI behaviors in the current Foldergram app.","frontmatter":{"title":"Features","description":"Verified product features and UI behaviors in the current Foldergram app."},"headers":[],"relativePath":"features.md","filePath":"features.md","lastUpdated":1774719654000}'),l={name:"features.md"};function r(s,e,d,n,h,c){return t(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="features" tabindex="-1">Features <a class="header-anchor" href="#features" aria-label="Permalink to &quot;Features&quot;">​</a></h1><p>This page documents what the current repository actually implements.</p><h2 id="home" tabindex="-1">Home <a class="header-anchor" href="#home" aria-label="Permalink to &quot;Home&quot;">​</a></h2><p>The home view is the primary feed surface.</p><p>It includes:</p><ul><li>three feed modes: Recent, Rediscover, and Random</li><li>a top Moments or Highlights section</li><li>feed-card avatar rings that can open an App Folder&#39;s avatar story in place when that folder has stories</li><li>an active home-feed video player that promotes one visible video card at a time and gives that card play, mute, and fullscreen controls</li><li>a startup scan state when the first index is still being built</li><li>a rebuild notice when the configured gallery root changed</li><li>desktop recommendations for folders based on recency, likes, and recent navigation</li><li>infinite loading for feed pagination</li></ul><h3 id="feed-mode-behavior" tabindex="-1">Feed mode behavior <a class="header-anchor" href="#feed-mode-behavior" aria-label="Permalink to &quot;Feed mode behavior&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Mode</th><th>What it does</th></tr></thead><tbody><tr><td>Recent</td><td>&quot;Newest posts first, with lighter runs from the same app folder.&quot;</td></tr><tr><td>Rediscover</td><td>&quot;Older posts resurface when they are worth another look.&quot;</td></tr><tr><td>Random</td><td>&quot;A fresh shuffle that stays steady while you browse.&quot;</td></tr></tbody></table><h2 id="reels" tabindex="-1">Reels <a class="header-anchor" href="#reels" aria-label="Permalink to &quot;Reels&quot;">​</a></h2><p>The dedicated reels view is available at <code>/reels</code>.</p><p>It includes:</p><ul><li>a video-only queue sourced from indexed library posts</li><li>a full-height scroll-snap deck</li><li>wheel, arrow-key, and page-up/page-down navigation in addition to direct scrolling</li><li>infinite loading with prefetch as you approach the end of the current queue</li><li>a desktop action bar for like/favorite toggle, details sidebar, folder shortcut, and original-video link</li><li>loading, empty, and error states</li><li>an app-wide default mode from Settings; the page itself does not expose an inline mode switch</li></ul><h3 id="queue-behavior" tabindex="-1">Queue behavior <a class="header-anchor" href="#queue-behavior" aria-label="Permalink to &quot;Queue behavior&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Mode</th><th>What it does</th></tr></thead><tbody><tr><td>Recommended</td><td>&quot;Affinity-ranked mix.&quot; It scores videos using freshness, likes, recent folder affinity, portrait fit, duration fit, and a deterministic seed, then reduces immediate repeats from the same folder when alternatives exist.</td></tr><tr><td>Recent</td><td>&quot;Newest videos first.&quot;</td></tr><tr><td>Random</td><td>&quot;Stable session shuffle.&quot;</td></tr></tbody></table><h2 id="explore" tabindex="-1">Explore <a class="header-anchor" href="#explore" aria-label="Permalink to &quot;Explore&quot;">​</a></h2><p>Explore is a dedicated full-screen shell with a darker visual treatment.</p><p>It combines:</p><ul><li>a random feed source</li><li>client-side ranking that boosts recent folder activity, liked folders, and recently opened folders</li><li>folder search across name, slug, breadcrumb, and path</li><li>local recent-search history stored in <code>localStorage</code></li></ul><p>Explore is a folder-search and serendipity surface, not a separate backend index.</p><h2 id="library" tabindex="-1">Library <a class="header-anchor" href="#library" aria-label="Permalink to &quot;Library&quot;">​</a></h2><p>Library lists every indexed folder and supports:</p><ul><li>free-text search</li><li>sorting by recent activity, post count, name, or path</li><li>quick navigation into folders</li><li>delete actions from a context menu</li></ul><h3 id="folder-deletion-behavior" tabindex="-1">Folder deletion behavior <a class="header-anchor" href="#folder-deletion-behavior" aria-label="Permalink to &quot;Folder deletion behavior&quot;">​</a></h3><p>Library supports two delete flows:</p><table tabindex="0"><thead><tr><th>Flow</th><th>Behavior</th></tr></thead><tbody><tr><td>Delete app folder</td><td>Deletes the folder&#39;s direct posts and their derivatives. Child app folders are kept. The source folder is only removed if it becomes empty.</td></tr><tr><td>Delete folder subtree</td><td>Removes the source folder subtree from disk, removes matching derivative subtrees, and deletes all affected indexed folders below that path.</td></tr></tbody></table><h2 id="folder-pages" tabindex="-1">Folder pages <a class="header-anchor" href="#folder-pages" aria-label="Permalink to &quot;Folder pages&quot;">​</a></h2><p>A folder page is available at:</p><ul><li><code>/folders/:slug</code></li><li><code>/:slug</code> as an alias</li></ul><p>Folder pages include:</p><ul><li>a folder header with avatar, posts counts, descriptions, and optional avatar-story opening</li><li>editable folder name and description via an admin &quot;Edit App Folder&quot; flow</li><li>a posts grid</li><li>highlight circles above the posts and reels tabs when the folder has story capsules</li><li>a reels tab when the folder contains videos</li><li>infinite loading</li></ul><p>The reels tab is a filtered view backed by the same folder endpoint using <code>mediaType=video</code>.</p><h2 id="folder-stories-and-highlights" tabindex="-1">Folder stories and highlights <a class="header-anchor" href="#folder-stories-and-highlights" aria-label="Permalink to &quot;Folder stories and highlights&quot;">​</a></h2><p>Foldergram can reserve <code>AppFolder/stories</code> as a story-style source for that folder.</p><p>In the default reserved-stories mode:</p><ul><li>direct media inside <code>AppFolder/stories</code> becomes the folder&#39;s avatar story set</li><li>each direct child folder inside <code>AppFolder/stories</code> becomes one highlight capsule</li><li>nested folders below a highlight are folded into that same capsule instead of becoming separate app folders</li><li>story media is hidden from normal folder, feed, search, and reels surfaces</li><li>the folder header avatar opens the avatar story when one exists</li><li>Home feed cards can open the same avatar story from the folder avatar ring</li><li>the shared stories modal is used for both the home-feed entry point and the folder-page entry points</li></ul><p>If the reserved root has no direct media but highlight capsules do exist, Foldergram can synthesize the avatar story from recent highlight media so the folder still has an avatar-story entry point.</p><h2 id="post-detail-and-modal-flow" tabindex="-1">Post detail and modal flow <a class="header-anchor" href="#post-detail-and-modal-flow" aria-label="Permalink to &quot;Post detail and modal flow&quot;">​</a></h2><p>The post detail route is <code>/image/:id</code>.</p><p>Behavior depends on how the route is opened:</p><ul><li>from another page, it can render as a modal over the background route</li><li>directly, it renders as a full page</li></ul><p>The detail view includes:</p><ul><li>image detail media sourced from either generated previews or originals, depending on <code>IMAGE_DETAIL_SOURCE</code></li><li>video detail playback that defaults to the generated preview source</li><li>an optional <code>HD</code> toggle for compatible higher-resolution MP4 originals</li><li>previous and next navigation within the same folder and active media filter</li><li>folder link and breadcrumb context</li><li>size, dimensions, MIME type, and duration metadata</li><li>like toggle</li><li>original-file link</li><li>an admin-only &quot;Set as Cover&quot; action to customize the folder avatar, which highlights dynamically if the image is already the cover</li><li>delete action with confirmation for admin sessions only</li></ul><h2 id="likes-and-favorites" tabindex="-1">Likes and Favorites <a class="header-anchor" href="#likes-and-favorites" aria-label="Permalink to &quot;Likes and Favorites&quot;">​</a></h2><p>Foldergram has two saved-items modes:</p><ul><li>signed-in <code>admin</code> and <code>viewer</code> sessions use shared SQLite likes through <code>GET /api/likes</code></li><li>anonymous public sessions use browser-local favorites stored in <code>localStorage</code></li></ul><p>The saved-items view:</p><ul><li>shows liked or favorited posts ordered by the most recent toggle in that mode</li><li>updates optimistically in the UI</li><li>drops deleted posts automatically when they are removed</li><li>stays intentionally separate between shared likes and local favorites</li></ul><p>There is no shared social layer behind either mode.</p><h2 id="moments" tabindex="-1">Moments <a class="header-anchor" href="#moments" aria-label="Permalink to &quot;Moments&quot;">​</a></h2><p>Home and <code>/moments/:id</code> expose either:</p><ul><li>date-driven Moments</li><li>fallback Highlights</li></ul><p>The selected set depends on timestamp coverage in the current library. The UI uses the same route name for both and adapts to the returned payload labels.</p><p>This is separate from folder stories and folder highlights sourced from reserved <code>stories/</code> folders.</p><h2 id="settings" tabindex="-1">Settings <a class="header-anchor" href="#settings" aria-label="Permalink to &quot;Settings&quot;">​</a></h2><p>Settings is the operational control surface for the library.</p><p>It exposes:</p><ul><li>admin-password controls</li><li>viewer password and public access controls</li><li>home and reels default feed-mode controls</li><li>stories-folders mode controls, migration notices, and a save-and-rescan flow</li><li>live scan status</li><li>storage and index status</li><li>last completed scan details</li><li>manual scan</li><li>thumbnail-only rebuild</li><li>library-index rebuild</li></ul><h3 id="access-protection" tabindex="-1">Access protection <a class="header-anchor" href="#access-protection" aria-label="Permalink to &quot;Access protection&quot;">​</a></h3><p>Settings can optionally enable role-based local access for the app.</p><p>That flow supports:</p><ul><li>turning the admin password on</li><li>changing the admin password</li><li>disabling protection again</li><li>enabling or disabling a separate viewer password</li><li>enabling anonymous public browse mode</li><li>rotating the viewer password without knowing the current one</li><li>signing the current browser session out</li></ul><p>Current non-admin behavior:</p><ul><li>viewers can browse the library and use shared likes</li><li>anonymous public visitors can browse immediately and use browser-local favorites</li><li><code>viewer</code> and <code>anonymous</code> sessions can elevate through <code>Unlock admin</code></li><li>non-admin sessions cannot open Settings</li><li>non-admin sessions cannot use Trash, delete actions, scans, or rebuild actions</li></ul><h3 id="rebuild-actions" tabindex="-1">Rebuild actions <a class="header-anchor" href="#rebuild-actions" aria-label="Permalink to &quot;Rebuild actions&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Action</th><th>What changes</th></tr></thead><tbody><tr><td>Scan Library</td><td>Runs a normal scan against the current gallery root.</td></tr><tr><td>Regenerate Thumbnails</td><td>Clears generated thumbnails and video poster images, then rebuilds them from indexed media only.</td></tr><tr><td>Rebuild Library Index</td><td>Clears indexed folders, posts, likes, folder scan state, and scan history, then rescans the active gallery root and reuses matching cached derivatives when possible. In lazy derivative mode it does not pre-generate missing thumbnails or previews.</td></tr></tbody></table><h2 id="theme-and-local-ui-preferences" tabindex="-1">Theme and local UI preferences <a class="header-anchor" href="#theme-and-local-ui-preferences" aria-label="Permalink to &quot;Theme and local UI preferences&quot;">​</a></h2><p>The client also persists a few local browser preferences:</p><ul><li>light or dark theme</li><li>whether videos start muted</li><li>last opened folder</li><li>recently opened folders</li><li>recent explore searches</li></ul><p>These are stored in <code>localStorage</code> and are not synced anywhere else.</p><h2 id="what-is-intentionally-missing" tabindex="-1">What is intentionally missing <a class="header-anchor" href="#what-is-intentionally-missing" aria-label="Permalink to &quot;What is intentionally missing&quot;">​</a></h2><p>The current repository does <strong>not</strong> implement:</p><ul><li>uploads from the UI</li><li>comments</li><li>messaging</li><li>notifications</li><li>multi-user accounts</li><li>remote multi-user permissions</li><li>cloud sync</li><li>hierarchical album navigation</li></ul>',72)])])}const m=a(l,[["render",r]]);export{p as __pageData,m as default};
